const { spawn } = require('child_process');

exports.handler = async (event) => {
  const record = event.Records[0];
  const s3Event = JSON.parse(record.body);

  const key = s3Event.Records[0].s3.object.key;
  const format = record.eventMetadata.format;

  const convertCommand = ['convert', key, '-format', format, '-quality', '80', '-strip', 'output.jpg'];

  try {
    await new Promise((resolve, reject) => {
      spawn('magick', convertCommand, { stdio: 'inherit' }, (error) => {
        if (error) {
          reject(error);
        } else {
          resolve();
        }
      });
    });

    // Upload the converted image to S3
    // ...

    return { statusCode: 200, body: 'Image converted successfully.' };
  } catch (error) {
    console.error(error);
    return { statusCode: 500, body: 'Error converting image.' };
  }
};